public boolean xyBalance(String str) {
    int lastXPosition = -1;
    int lastYPosition = -1;

    for (int i = 0; i < str.length(); i++) {
        char currentChar = str.charAt(i);
        if (currentChar == 'x') {
            lastXPosition = i;
        } else if (currentChar == 'y') {
            lastYPosition = i;
        }
    }

    return lastYPosition >= lastXPosition;
}

